ll dp1[110000], dp2[110000], ans[110000];



void dfs1(ll x, ll p = -1) {

    ll prod = 1;

    for(auto e : g[x]) {

        if(e == p) continue;

        dfs1(e, x);

        prod *= dp1[e];

        prod %= M;

    }

    dp1[x] = prod + 1;

    dp1[x] %= M;

}



void dfs2(ll x, ll p = -1) {

    if(p == -1) dp2[x] = 1;



    ll m = g[x].size();

    vll lprod(m, 1), rprod(m, 1);

    rep(i, m) {

        ll to = g[x][i];

        if(i-1 >= 0) lprod[i] = lprod[i-1];

        if(to == p) continue;

        (lprod[i] *= dp1[to]) %= M;

    }



    for(ll i = m-1; i >= 0; i--) {

        ll to = g[x][i];

        if(i+1 <= m-1) rprod[i] = rprod[i+1];

        if(to == p) continue;

        (rprod[i] *= dp1[to]) %= M;

    }



    rep(i, m) {

        ll to = g[x][i];

        if(to == p) continue;



        ll prod = dp2[x];

        if(i-1 >= 0) (prod *= lprod[i-1]) %= M;

        if(i+1 <= m-1) (prod *= rprod[i+1]) %= M;

        dp2[to] = (prod + 1) % M;

        dfs2(to, x);

    }

}



void dfs3(ll x, ll p = -1) {

    ans[x] = dp2[x];

    for(auto to : g[x]) {

        if(to == p) continue;

        ans[x] *= dp1[to];

        ans[x] %= M;

        dfs3(to, x);

    }

}



